const mongoose = require('mongoose');

const transactionSchema = new mongoose.Schema(
  {
    memberId: { type: mongoose.Schema.Types.ObjectId, ref: 'Member', required: true },
    memberName: { type: String, required: true },
    month: { type: String, required: true },
    loanAmount: { type: Number, default: 0 },
    paidAmount: { type: Number, default: 0 },
    remainingAmount: { type: Number, default: 0 },
    interest: { type: Number, default: 0 },
    monthlyCDAmount: { type: Number, default: 0 },
    adjCDAmt: { type: Number, default: 0 },
    totalCumulativeCDAmt: { type: Number, default: 0 },
    totalCDAmt: { type: Number, default: 0 },
    monthlyDividend: { type: Number, default: 0 },
    totalDividend: { type: Number, default: 0 },
    rpd25RollingPrincipalDeposit: { type: Number, default: 0 }
  },
  { timestamps: true }
);

module.exports = mongoose.model('Transaction', transactionSchema);
